class SyncData {
  final String id;
  final String type;
  final Map<String, dynamic> payload;
  final DateTime timestamp;

  SyncData({
    required this.id,
    required this.type,
    required this.payload,
    required this.timestamp,
  });

  factory SyncData.fromJson(Map<String, dynamic> json) {
    return SyncData(
      id: json['id'] as String,
      type: json['type'] as String,
      payload: json['payload'] as Map<String, dynamic>,
      timestamp: DateTime.parse(json['timestamp'] as String),
    );
  }

  Map<String, dynamic> toJson() => {
        'id': id,
        'type': type,
        'payload': payload,
        'timestamp': timestamp.toIso8601String(),
      };
}

class SyncResult {
  final List<SyncData> received;
  final List<String> acknowledgedIds;
  final DateTime serverTimestamp;

  SyncResult({
    required this.received,
    required this.acknowledgedIds,
    required this.serverTimestamp,
  });

  factory SyncResult.fromJson(Map<String, dynamic> json) {
    return SyncResult(
      received: (json['data'] as List<dynamic>)
          .map((e) => SyncData.fromJson(e as Map<String, dynamic>))
          .toList(),
      acknowledgedIds: (json['acknowledged'] as List<dynamic>)
          .map((e) => e as String)
          .toList(),
      serverTimestamp: DateTime.parse(json['server_timestamp'] as String),
    );
  }
}

