class ApiClient {
  static const String _baseUrl = 'https://api.example.com';
  static const Duration _timeout = Duration(seconds: 30);
  static const int _maxRetries = 3;
  static const Duration _retryDelay = Duration(seconds: 1);

  final http.Client _httpClient;
  final TokenStorage _tokenStorage;
  final Completer<void>? _refreshCompleter = null;
  bool _isRefreshing = false;
  Completer<AuthTokens>? _activeRefreshCompleter;

  ApiClient({
    http.Client? httpClient,
    TokenStorage? tokenStorage,
  })  : _httpClient = httpClient ?? http.Client(),
        _tokenStorage = tokenStorage ?? SecureTokenStorage();

  void dispose() {
    _httpClient.close();
  }

  // --- Private Helpers ---

  Map<String, String> _baseHeaders() => {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
        'X-Platform': Platform.isIOS ? 'ios' : 'android',
      };

  Future<Map<String, String>> _authenticatedHeaders() async {
    final tokens = await _getValidTokens();
    if (tokens == null) {
      throw AuthenticationException(message: 'No authentication tokens available');
    }
    return {
      ..._baseHeaders(),
      'Authorization': 'Bearer ${tokens.accessToken}',
    };
  }

  Future<AuthTokens?> _getValidTokens() async {
    final tokens = await _tokenStorage.getTokens();
    if (tokens == null) return null;

    if (tokens.isExpired) {
      return _refreshTokens(tokens);
    }

    return tokens;
  }

  Future<AuthTokens> _refreshTokens(AuthTokens currentTokens) async {
    // Prevent concurrent refresh requests
    if (_isRefreshing && _activeRefreshCompleter != null) {
      return _activeRefreshCompleter!.future;
    }

    _isRefreshing = true;
    _activeRefreshCompleter = Completer<AuthTokens>();

    try {
      final response = await _httpClient
          .post(
            Uri.parse('$_baseUrl/auth/refresh'),
            headers: _baseHeaders(),
            body: jsonEncode({
              'refresh_token': currentTokens.refreshToken,
            }),
          )
          .timeout(_timeout);

      if (response.statusCode == 200) {
        final newTokens = AuthTokens.fromJson(
          jsonDecode(response.body) as Map<String, dynamic>,
        );
        await _tokenStorage.saveTokens(newTokens);
        _activeRefreshCompleter!.complete(newTokens);
        return newTokens;
      } else {
        await _tokenStorage.clearTokens();
        final error = AuthenticationException(
          message: 'Token refresh failed',
        );
        _activeRefreshCompleter!.completeError(error);
        throw error;
      }
    } catch (e) {
      if (!_activeRefreshCompleter!.isCompleted) {
        _activeRefreshCompleter!.completeError(e);
      }
      rethrow;
    } finally {
      _isRefreshing = false;
      _activeRefreshCompleter = null;
    }
  }

  Future<http.Response> _makeRequest(
    Future<http.Response> Function() requestFn, {
    int retries = 0,
  }) async {
    try {
      final response = await requestFn().timeout(_timeout);
      return response;
    } on SocketException catch (e) {
      if (retries < _maxRetries) {
        await Future.delayed(_retryDelay * (retries + 1));
        return _makeRequest(requestFn, retries: retries + 1);
      }
      throw NetworkException('No internet connection: ${e.message}');
    } on TimeoutException {
      if (retries < _maxRetries) {
        await Future.delayed(_retryDelay * (retries + 1));
        return _makeRequest(requestFn, retries: retries + 1);
      }
      throw NetworkException('Request timed out');
    } on http.ClientException catch (e) {
      if (retries < _maxRetries) {
        await Future.delayed(_retryDelay * (retries + 1));
        return _makeRequest(requestFn, retries: retries + 1);
      }
      throw NetworkException('Client error: ${e.message}');
    }
  }

  T _handleResponse<T>(http.Response response, T Function(Map<String, dynamic>) parser) {
    final body = response.body.isNotEmpty
        ? jsonDecode(response.body) as Map<String, dynamic>
        : <String, dynamic>{};

    switch (response.statusCode) {
      case 200:
      case 201:
        return parser(body);
      case 401:
        throw AuthenticationException(
          message: body['message'] as String? ?? 'Unauthorized',
        );
      case 403:
        throw ApiException(
          statusCode: 403,
          message: body['message'] as String? ?? 'Forbidden',
          errorCode: body['error_code'] as String?,
        );
      case 404:
        throw ApiException(
          statusCode: 404,
          message: body['message'] as String? ?? 'Not found',
          errorCode: body['error_code'] as String?,
        );
      case 422:
        throw ApiException(
          statusCode: 422,
          message: body['message'] as String? ?? 'Validation error',
          errorCode: body['error_code'] as String?,
        );
      case 429:
        throw ApiException(
          statusCode: 429,
          message: 'Rate limit exceeded. Please try again later.',
          errorCode: 'RATE_LIMITED',
        );
      default:
        throw ApiException(
          statusCode: response.statusCode,
          message: body['message'] as String? ?? 'An unexpected error occurred',
          errorCode: body['error_code'] as String?,
        );
    }
  }

  // --- Authentication ---

  Future<AuthTokens> login({
    required String email,
    required String password,
  }) async {
    // Basic input validation
    if (email.isEmpty || password.isEmpty) {
      throw ArgumentError('Email and password must not be empty');
    }

    final response = await _makeRequest(
      () => _httpClient.post(
        Uri.parse('$_baseUrl/auth/login'),
        headers: _baseHeaders(),
        body: jsonEncode({
          'email': email.trim(),
          'password': password,
        }),
      ),
    );

    final tokens = _handleResponse(response, AuthTokens.fromJson);
    await _tokenStorage.saveTokens(tokens);
    return tokens;
  }

  Future<AuthTokens> register({
    required String email,
    required String password,
    required String displayName,
  }) async {
    if (email.isEmpty || password.isEmpty || displayName.isEmpty) {
      throw ArgumentError('All fields are required');
    }

    if (password.length < 8) {
      throw ArgumentError('Password must be at least 8 characters');
    }

    final response = await _makeRequest(
      () => _httpClient.post(
        Uri.parse('$_baseUrl/auth/register'),
        headers: _baseHeaders(),
        body: jsonEncode({
          'email': email.trim(),
          'password': password,
          'display_name': displayName.trim(),
        }),
      ),
    );

    final tokens = _handleResponse(response, AuthTokens.fromJson);
    await _tokenStorage.saveTokens(tokens);
    return tokens;
  }

  Future<void> logout() async {
    try {
      final headers = await _authenticatedHeaders();
      await _makeRequest(
        () => _httpClient.post(
          Uri.parse('$_baseUrl/auth/logout'),
          headers: headers,
        ),
      );
    } catch (_) {
      // Best-effort server-side logout; always clear local tokens
    } finally {
      await _tokenStorage.clearTokens();
    }
  }

  Future<bool> get isAuthenticated async {
    final tokens = await _tokenStorage.getTokens();
    return tokens != null;
  }

  // --- User Profile ---

  Future<UserProfile> getProfile() async {
    final headers = await _authenticatedHeaders();

    final response = await _makeRequest(
      () => _httpClient.get(
        Uri.parse('$_baseUrl/user/profile'),
        headers: headers,
      ),
    );

    return _handleResponse(response, UserProfile.fromJson);
  }

  Future<UserProfile> updateProfile({
    String? displayName,
    String? avatarUrl,
  }) async {
    final headers = await _authenticatedHeaders();

    final body = <String, dynamic>{};
    if (displayName != null) body['display_name'] = displayName.trim();
    if (avatarUrl != null) body['avatar_url'] = avatarUrl.trim();

    if (body.isEmpty) {
      throw ArgumentError('At least one field must be provided for update');
    }

    final response = await _makeRequest(
      () => _httpClient.patch(
        Uri.parse('$_baseUrl/user/profile'),
        headers: headers,
        body: jsonEncode(body),
      ),
    );

    return _handleResponse(response, UserProfile.fromJson);
  }

  Future<void> changePassword({
    required String currentPassword,
    required String newPassword,
  }) async {
    if (currentPassword.isEmpty || newPassword.isEmpty) {
      throw ArgumentError('Passwords must not be empty');
    }

    if (newPassword.length < 8) {
      throw ArgumentError('New password must be at least 8 characters');
    }

    if (currentPassword == newPassword) {
      throw ArgumentError('New password must differ from current password');
    }

    final headers = await _authenticatedHeaders();

    final response = await _makeRequest(
      () => _httpClient.post(
        Uri.parse('$_baseUrl/user/change-password'),
        headers: headers,
        body: jsonEncode({
          'current_password': currentPassword,
          'new_password': newPassword,
        }),
      ),
    );

    _handleResponse(response, (json) => null);
  }

  Future<void> deleteAccount() async {
    final headers = await _authenticatedHeaders();

    final response = await _makeRequest(
      () => _httpClient.delete(
        Uri.parse('$_baseUrl/user/profile'),
        headers: headers,
      ),
    );

    _handleResponse(response, (json) => null);
    await _tokenStorage.clearTokens();
  }

  // --- Data Synchronization ---

  Future<SyncResult> syncData({
    required List<SyncData> localChanges,
    DateTime? lastSyncTimestamp,
  }) async {
    final headers = await _authenticatedHeaders();

    final body = <String, dynamic>{
      'changes': localChanges.map((e) => e.toJson()).toList(),
    };

    if (lastSyncTimestamp != null) {
      body['last_sync'] = lastSyncTimestamp.toIso8601String();
    }

    final response = await _makeRequest(
      () => _httpClient.post(
        Uri.parse('$_baseUrl/sync'),
        headers: headers,
        body: jsonEncode(body),
      ),
    );

    return _handleResponse(response, SyncResult.fromJson);
  }

  Future<List<SyncData>> fetchChanges({
    required DateTime since,
    int limit = 100,
    int offset = 0,
  }) async {
    final headers = await _authenticatedHeaders();

    final queryParams = {
      'since': since.toIso8601String(),
      'limit': limit.toString(),
      'offset': offset.toString(),
    };

    final uri = Uri.parse('$_baseUrl/sync/changes').replace(
      queryParameters: queryParams,
    );

    final response = await _makeRequest(
      () => _httpClient.get(uri, headers: headers),
    );

    return _handleResponse(
      response,
      (json) => (json['data'] as List<dynamic>)
          .map((e) => SyncData.fromJson(e as Map<String, dynamic>))
          .toList(),
    );
  }

  Future<void> pushChanges(List<SyncData> changes) async {
    if (changes.isEmpty) return;

    final headers = await _authenticatedHeaders();

    // Batch in chunks of 50 to avoid oversized payloads
    const batchSize = 50;
    for (var i = 0; i < changes.length; i += batchSize) {
      final batch = changes.sublist(
        i,
        i + batchSize > changes.length ? changes.length : i + batchSize,
      );

      final response = await _makeRequest(
        () => _httpClient.post(
          Uri.parse('$_baseUrl/sync/push'),
          headers: headers,
          body: jsonEncode({
            'changes': batch.map((e) => e.toJson()).toList(),
          }),
        ),
      );

      _handleResponse(response, (json) => null);
    }
  }

  Future<DateTime> getServerTimestamp() async {
    final headers = await _authenticatedHeaders();

    final response = await _makeRequest(
      () => _httpClient.get(
        Uri.parse('$_baseUrl/sync/timestamp'),
        headers: headers,
      ),
    );

    return _handleResponse(
      response,
      (json) => DateTime.parse(json['timestamp'] as String),
    );
  }
}

// --- Sync Manager for periodic synchronization ---

class SyncManager {
  final ApiClient _apiClient;
  Timer? _syncTimer;
  DateTime? _lastSyncTimestamp;
  bool _isSyncing = false;

  final StreamController<SyncStatus> _statusController =
      StreamController<SyncStatus>.broadcast();

  Stream<SyncStatus> get statusStream => _statusController.stream;

  final List<SyncData> _pendingChanges = [];

  SyncManager({required ApiClient apiClient}) : _apiClient = apiClient;

  void startPeriodicSync({Duration interval = const Duration(minutes: 5)}) {
    stopPeriodicSync();
    _syncTimer = Timer.periodic(interval, (_) => performSync());
    // Perform an immediate sync
    performSync();
  }

  void stopPeriodicSync() {
    _syncTimer?.cancel();
    _syncTimer = null;
  }

  void addPendingChange(SyncData change) {
    _pendingChanges.add(change);
  }

  Future<void> performSync() async {
    if (_isSyncing) return;

    _isSyncing = true;
    _statusController.add(SyncStatus.syncing);

    try {
      final changesToSync = List<SyncData>.from(_pendingChanges);

      final result = await _apiClient.syncData(
        localChanges: changesToSync,
        lastSyncTimestamp: _lastSyncTimestamp,
      );

      // Remove acknowledged changes from pending
      _pendingChanges.removeWhere(
        (change) => result.acknowledgedIds.contains(change.id),
      );

      _lastSyncTimestamp = result.serverTimestamp;
      _statusController.add(SyncStatus.completed);

      if (kDebugMode) {
        print(
          'Sync completed: ${result.received.length} received, '
          '${result.acknowledgedIds.length} acknowledged',
        );
      }
    } on AuthenticationException {
      _statusController.add(SyncStatus.authError);
    } on NetworkException {
      _statusController.add(SyncStatus.networkError);
    } catch (e) {
      _statusController.add(SyncStatus.error);
      if (kDebugMode) {
        print('Sync error: $e');
      }
    } finally {
      _isSyncing = false;
    }
  }

  void dispose() {
    stopPeriodicSync();
    _statusController.close();
  }
}

enum SyncStatus {
  idle,
  syncing,
  completed,
  error,
  networkError,
  authError,
}

